INSERT INTO `announcement` VALUES (5,'회사 창립기념일',47,'<p>회사 창립기념일은 10월 13일 입니다.</p><p>&nbsp;</p>',12,'2023-10-13 05:37:47'),(6,'[공지] 뮤지컬 <혐오스런 마츠코의 일생> 특별 할인 안내',47,'<p style=\"line-height: 24px; font-family: 굴림;\"><span style=\"line-height: 26.6667px; margin-top: 0px; margin-bottom: 0px; font-family: &quot;맑은 고딕&quot;; font-size: 10pt;\">안녕하세요. 영업팀 고은선입니다.&nbsp;</span></p><p style=\"line-height: 24px; font-family: 굴림;\"><span style=\"line-height: 26.6667px; margin-top: 0px; margin-bottom: 0px; font-family: &quot;맑은 고딕&quot;; font-size: 10pt;\">&nbsp;</span></p><p style=\"line-height: 24px; font-family: 굴림;\"><span style=\"line-height: 26.6667px; margin-top: 0px; margin-bottom: 0px; font-family: &quot;맑은 고딕&quot;; font-size: 10pt;\"><span style=\"font-size: 10pt; line-height: 26.6667px; margin-top: 0px; margin-bottom: 0px;\">뮤지컬<strong>&nbsp;<span style=\"font-size: 11pt; line-height: 26.6667px; margin-top: 0px; margin-bottom: 0px; color: rgb(255, 0, 127);\">혐오스런 마츠코의 일생</span></strong></span>&nbsp;티켓을</span>&nbsp;<span style=\"line-height: 26.6667px; margin-top: 0px; margin-bottom: 0px; font-family: &quot;맑은 고딕&quot;; font-size: 10pt;\">다우기술 임직원 분들이 할인된 가격으로 구매할 수 있어 안내드립니다.</span></p><p style=\"line-height: 24px; font-family: 굴림;\"><span style=\"line-height: 26.6667px; margin-top: 0px; margin-bottom: 0px; font-family: &quot;맑은 고딕&quot;; font-size: 10pt;\">&nbsp;</span></p><p style=\"line-height: 26.6667px; font-family: 돋움, dotum, AppleGothic, arial, Helvetica, sans-serif; font-size: 10pt;\"><span style=\"color: rgb(86, 86, 86); font-size: 10pt; line-height: 26.6667px; margin-top: 0px; margin-bottom: 0px;\"><i>뮤지컬 ‹혐오스런 마츠코의 일생›은 야마다 무네키의 동명 소설을 원작으로 한 작품으로 한 여자의 잔혹한 삶을 다룬 뮤지컬이다.</i></span></p><p style=\"line-height: 26.6667px; font-family: 돋움, dotum, AppleGothic, arial, Helvetica, sans-serif; font-size: 10pt;\"><span style=\"color: rgb(86, 86, 86); font-size: 10pt; line-height: 26.6667px; margin-top: 0px; margin-bottom: 0px;\"><i>31년 전 착하고 바른 중학교 교사였던 마츠코가 괴물 같은 폐인이 되기까지 벌어지는 사건들을 보여준다.</i></span></p><p style=\"line-height: 24px; font-family: 굴림;\"><i style=\"color: rgb(86, 86, 86); font-size: 10pt; font-family: &quot;맑은 고딕&quot;;\">마츠코의 슬프도록 아름다운 일생을 섬세하고 감성적인 음악과 드라마로 선보인다.</i></p><p style=\"line-height: 26.6667px; font-family: 돋움, dotum, AppleGothic, arial, Helvetica, sans-serif; font-size: 10pt;\">&nbsp;</p><p style=\"line-height: 26.6667px; font-family: 돋움, dotum, AppleGothic, arial, Helvetica, sans-serif; font-size: 10pt;\"><b style=\"color: rgb(0, 85, 255); font-size: 10pt;\"><span style=\"line-height: 26.6667px; margin-top: 0px; margin-bottom: 0px; font-size: 10pt;\"><span style=\"line-height: 26.6667px; margin-top: 0px; margin-bottom: 0px; font-size: 10pt;\"><span style=\"font-size: 10pt; line-height: 26.6667px; margin-top: 0px; margin-bottom: 0px;\">★ &lt;혐오스런 마츠코의 일생&gt; 특별 할인 안내&nbsp;</span></span></span><span style=\"line-height: 26.6667px; margin-top: 0px; margin-bottom: 0px; font-size: 10pt;\"><span style=\"line-height: 26.6667px; margin-top: 0px; margin-bottom: 0px; font-size: 10pt;\"><span style=\"font-size: 10pt; line-height: 26.6667px; margin-top: 0px; margin-bottom: 0px;\">★</span></span></span></b><span style=\"color: rgb(0, 85, 255); font-size: 10pt;\">&nbsp;</span></p><p style=\"line-height: 24px; font-family: 굴림;\"><span style=\"line-height: 26.6667px; margin-top: 0px; margin-bottom: 0px; font-family: &quot;맑은 고딕&quot;; font-size: 10pt;\">- 관람기간 :&nbsp;</span><span style=\"font-family: &quot;맑은 고딕&quot;; font-size: 10pt; line-height: 24px; margin-top: 0px; margin-bottom: 0px;\">2017/10/27-2017/11/12 (추가 티켓오픈 시 연장 예정)&nbsp;</span></p><p style=\"line-height: 24px; font-family: 굴림;\"><span style=\"font-family: &quot;맑은 고딕&quot;; font-size: 10pt; line-height: 24px; margin-top: 0px; margin-bottom: 0px;\"><span style=\"font-size: 10pt; line-height: 24px; margin-top: 0px; margin-bottom: 0px;\"><span style=\"font-size: 10pt; line-height: 24px; margin-top: 0px; margin-bottom: 0px;\"><span style=\"font-size: 10pt; line-height: 24px; margin-top: 0px; margin-bottom: 0px; color: rgb(140, 140, 140);\">&nbsp; &nbsp;※ 오늘부터 예매 가능</span></span></span></span></p><p style=\"line-height: 24px; font-family: 굴림;\"><span style=\"line-height: 26.6667px; margin-top: 0px; margin-bottom: 0px; font-family: &quot;맑은 고딕&quot;; font-size: 10pt;\">- 구매수량 : 1인 4매까지 구매 가능</span></p><p style=\"line-height: 24px; font-family: 굴림;\"><span style=\"line-height: 26.6667px; margin-top: 0px; margin-bottom: 0px; font-family: &quot;맑은 고딕&quot;; font-size: 10pt;\"><span style=\"line-height: 26.6667px; margin-top: 0px; margin-bottom: 0px; font-size: 10pt;\"><span style=\"font-size: 10pt; line-height: 26.6667px; margin-top: 0px; margin-bottom: 0px;\"><span style=\"font-size: 13.3333px; line-height: 26.6667px; margin-top: 0px; margin-bottom: 0px;\">- 상 영 관 : 두산아트센터 연강홀 (서울시 종로구)</span></span></span></span></p><p style=\"line-height: 24px; font-family: 굴림;\"><span style=\"line-height: 26.6667px; margin-top: 0px; margin-bottom: 0px; font-family: &quot;맑은 고딕&quot;; font-size: 10pt;\">- 할 인 가 :&nbsp;</span><b style=\"color: rgb(78, 78, 78); background-color: rgb(255, 187, 0); font-family: &quot;맑은 고딕&quot;; font-size: 10pt;\"><span style=\"color: rgb(17, 17, 17); background-image: initial; background-position: initial; background-size: initial; background-repeat: initial; background-attachment: initial; background-origin: initial; background-clip: initial; font-size: 10pt; line-height: 24px; margin-top: 0px; margin-bottom: 0px;\">R 55,000원&nbsp;/ S 40,000원&nbsp;/&nbsp;시야제한석&nbsp;25,000원&nbsp;(약&nbsp;35%&nbsp;할인)</span></b></p><p style=\"line-height: 24px; font-family: 굴림;\"><span style=\"font-family: &quot;맑은 고딕&quot;; font-size: 10pt; line-height: 24px; margin-top: 0px; margin-bottom: 0px;\"><span style=\"font-size: 10pt; line-height: 24px; margin-top: 0px; margin-bottom: 0px;\"><span style=\"font-size: 10pt; line-height: 24px; margin-top: 0px; margin-bottom: 0px; color: rgb(17, 17, 17);\">&nbsp;&nbsp;</span><span style=\"font-size: 10pt; line-height: 24px; margin-top: 0px; margin-bottom: 0px; color: rgb(140, 140, 140);\">정 상 가&nbsp;</span></span><span style=\"color: rgb(140, 140, 140); font-size: 10pt; line-height: 24px; margin-top: 0px; margin-bottom: 0px;\">:&nbsp;<strong>R 88,000</strong></span><strong><span style=\"color: rgb(140, 140, 140); font-size: 10pt; line-height: 24px; margin-top: 0px; margin-bottom: 0px;\">원</span><span style=\"color: rgb(140, 140, 140); font-size: 10pt; line-height: 24px; margin-top: 0px; margin-bottom: 0px;\">&nbsp;/ S 66,000</span><span style=\"color: rgb(140, 140, 140); font-size: 10pt; line-height: 24px; margin-top: 0px; margin-bottom: 0px;\">원</span><span style=\"color: rgb(140, 140, 140); font-size: 10pt; line-height: 24px; margin-top: 0px; margin-bottom: 0px;\">&nbsp;/&nbsp;</span><span style=\"color: rgb(140, 140, 140); font-size: 10pt; line-height: 24px; margin-top: 0px; margin-bottom: 0px;\">시야제한석</span><span style=\"color: rgb(140, 140, 140); font-size: 10pt; line-height: 24px; margin-top: 0px; margin-bottom: 0px;\">&nbsp;44,000</span><span style=\"color: rgb(140, 140, 140); font-size: 10pt; line-height: 24px; margin-top: 0px; margin-bottom: 0px;\">원</span></strong></span></p><p style=\"line-height: 24px; font-family: 굴림;\"><span style=\"line-height: 26.6667px; margin-top: 0px; margin-bottom: 0px; font-family: &quot;맑은 고딕&quot;; font-size: 10pt;\">-&nbsp;</span><span style=\"line-height: 26.6667px; margin-top: 0px; margin-bottom: 0px; font-family: &quot;맑은 고딕&quot;; font-size: 10pt;\">티켓 수령시, 사원증 or 명함 + 신분증 필히 지참! (미지참시 현금차액발생)</span></p>',25,'2023-10-13 05:43:41'),(12,'[공지] 신종 코로나바이러스감염증 예방수칙 안내',47,'<p style=\"line-height: 20px; font-family: &quot;Noto Sans KR&quot;; font-size: 10pt;\">안녕하세요. 인사팀 김지연입니다.</p><p style=\"line-height: 20px; font-family: &quot;Noto Sans KR&quot;; font-size: 10pt;\">최근 발생한 신종 코로나바이러스와 관련하여 인사팀에서 안내 말씀 드립니다.</p><p style=\"line-height: 20px; font-family: &quot;Noto Sans KR&quot;; font-size: 10pt;\">&nbsp;